import { useRef, useCallback, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { CalendarEvent } from '../types';
import { SLOT_HEIGHT, fmtDisplayTime } from '../utils/dateUtils';

// ─── Ghost element (week view live-time indicator) ────────────────────────────

let ghostEl: HTMLDivElement | null = null;

function createGhost(event: CalendarEvent, timeStr: string): HTMLDivElement {
  if (ghostEl) ghostEl.remove();
  const el = document.createElement('div');
  el.id = 'df-drag-ghost';
  el.innerHTML = `
    <div style="font-weight:600;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${event.title}</div>
    <div id="df-ghost-time" style="font-size:11px;opacity:0.85;margin-top:2px">${timeStr}</div>
  `;
  Object.assign(el.style, {
    position:      'fixed',
    pointerEvents: 'none',
    zIndex:        '9999',
    background:    event.color,
    color:         '#fff',
    padding:       '6px 10px',
    borderRadius:  '7px',
    minWidth:      '110px',
    maxWidth:      '180px',
    boxShadow:     '0 4px 16px rgba(0,0,0,0.25)',
    opacity:       '0.93',
    transform:     'translate(-50%, -110%)',
    transition:    'none',
    userSelect:    'none',
  });
  document.body.appendChild(el);
  ghostEl = el;
  return el;
}

function updateGhostTime(timeStr: string) {
  const el = document.getElementById('df-ghost-time');
  if (el) el.textContent = timeStr;
}

function removeGhost() {
  ghostEl?.remove();
  ghostEl = null;
}

// ─── Snap helper ────────────────────────────────────────────────────────────

function snapToMinutes(rawMinutes: number, snap = 15): number {
  return Math.round(rawMinutes / snap) * snap;
}

function minutesToTimeStr(totalMinutes: number): string {
  const clamped = Math.max(0, Math.min(totalMinutes, 23 * 60 + 59));
  const h = Math.floor(clamped / 60);
  const m = clamped % 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
}

function durationMinutes(start: string, end: string): number {
  const [sh, sm] = start.split(':').map(Number);
  const [eh, em] = end.split(':').map(Number);
  return Math.max((eh * 60 + em) - (sh * 60 + sm), 15);
}

// ─── Hook ─────────────────────────────────────────────────────────────────────

export interface UseDragEventReturn {
  getChipDragProps: (event: CalendarEvent) => {
    draggable: true;
    onDragStart: (e: React.DragEvent) => void;
    onDragEnd:   (e: React.DragEvent) => void;
  };
  getWeekColDropProps: (
    dateStr: string,
    colRef: React.RefObject<HTMLDivElement>
  ) => {
    onDragOver:  (e: React.DragEvent) => void;
    onDragEnter: (e: React.DragEvent) => void;
    onDragLeave: (e: React.DragEvent) => void;
    onDrop:      (e: React.DragEvent) => void;
  };
  getMonthCellDropProps: (dateStr: string) => {
    onDragOver:  (e: React.DragEvent) => void;
    onDragEnter: (e: React.DragEvent) => void;
    onDragLeave: (e: React.DragEvent) => void;
    onDrop:      (e: React.DragEvent) => void;
  };
}

export function useDragEvent(): UseDragEventReturn {
  const { state, dispatch } = useApp();

  // Track the active drag
  const draggingEventRef = useRef<CalendarEvent | null>(null);
  const grabOffsetYRef   = useRef(0); // px from chip top where user grabbed

  // Per-element enter counters to fix stuck highlights
  const enterCounters = useRef<WeakMap<Element, number>>(new WeakMap());

  const addHighlight = (el: Element) => {
    el.classList.add('df-drag-over');
  };
  const removeHighlight = (el: Element) => {
    el.classList.remove('df-drag-over');
  };

  // Clean up all highlights on drag end (safety net)
  const clearAllHighlights = () => {
    document.querySelectorAll('.df-drag-over').forEach(el => {
      el.classList.remove('df-drag-over');
    });
    enterCounters.current = new WeakMap();
  };

  // ── Ghost mouse tracking (week view) ────────────────────────────────────────
  // We attach a mousemove listener during drag to move the ghost and
  // calculate the snapped time. We also store the last computed time
  // so the drop handler can use it.
  const lastSnappedTimeRef = useRef<string>('');
  const lastSnappedDateRef = useRef<string>('');

  // ── Chip drag props ────────────────────────────────────────────────────────
  const getChipDragProps = useCallback((event: CalendarEvent) => ({
    draggable: true as const,

    onDragStart: (e: React.DragEvent) => {
      draggingEventRef.current = event;

      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      grabOffsetYRef.current = e.clientY - rect.top;

      // Invisible native drag image
      const blank = document.createElement('div');
      blank.style.cssText = 'position:fixed;top:-9999px;left:-9999px;width:1px;height:1px;';
      document.body.appendChild(blank);
      e.dataTransfer.setDragImage(blank, 0, 0);
      setTimeout(() => blank.remove(), 0);

      e.dataTransfer.effectAllowed = 'move';

      // Start ghost
      const [sh, sm] = event.start.split(':').map(Number);
      const timeLabel = fmtDisplayTime(event.start);
      createGhost(event, timeLabel);
      lastSnappedTimeRef.current = event.start;
      lastSnappedDateRef.current = event.date;

      dispatch({ type: 'SET_DRAGGING', payload: event.id });
    },

    onDragEnd: (_e: React.DragEvent) => {
      removeGhost();
      clearAllHighlights();
      draggingEventRef.current = null;
      dispatch({ type: 'SET_DRAGGING', payload: null });
    },
  }), [dispatch]);

  // Ghost follows mouse globally during drag
  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!ghostEl || !draggingEventRef.current) return;
      ghostEl.style.left = `${e.clientX}px`;
      ghostEl.style.top  = `${e.clientY}px`;
    };
    window.addEventListener('mousemove', onMouseMove);
    return () => window.removeEventListener('mousemove', onMouseMove);
  }, []);

  // ── Week column drop props ─────────────────────────────────────────────────
  // We attach to the whole day column div (not individual hour slots) to avoid
  // the child-element enter/leave flickering problem.
  const getWeekColDropProps = useCallback((
    dateStr: string,
    scrollRef: React.RefObject<HTMLDivElement>
  ) => ({
    onDragEnter: (e: React.DragEvent) => {
      e.preventDefault();
      const el = e.currentTarget as Element;
      const count = (enterCounters.current.get(el) ?? 0) + 1;
      enterCounters.current.set(el, count);
      if (count === 1) addHighlight(el);
    },

    onDragLeave: (e: React.DragEvent) => {
      const el = e.currentTarget as Element;
      const count = Math.max((enterCounters.current.get(el) ?? 1) - 1, 0);
      enterCounters.current.set(el, count);
      if (count === 0) removeHighlight(el);
    },

    onDragOver: (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';

      const ev = draggingEventRef.current;
      if (!ev || !scrollRef.current) return;

      // Calculate snapped time from cursor position within the scroll container
      const scrollEl  = scrollRef.current;
      const scrollRect = scrollEl.getBoundingClientRect();
      // e.clientY relative to the scroll container top, plus scroll offset,
      // minus the sticky header height (56px)
      const relY = (e.clientY - scrollRect.top) + scrollEl.scrollTop - 56;
      const rawMinutes = (relY / SLOT_HEIGHT) * 60;
      const snappedMinutes = snapToMinutes(rawMinutes);
      const newStart = minutesToTimeStr(snappedMinutes);

      if (newStart !== lastSnappedTimeRef.current || dateStr !== lastSnappedDateRef.current) {
        lastSnappedTimeRef.current = newStart;
        lastSnappedDateRef.current = dateStr;
        const dur = durationMinutes(ev.start, ev.end);
        const endMinutes = snappedMinutes + dur;
        const newEnd = minutesToTimeStr(endMinutes);
        updateGhostTime(`${fmtDisplayTime(newStart)} – ${fmtDisplayTime(newEnd)}`);
      }
    },

    onDrop: (e: React.DragEvent) => {
      e.preventDefault();
      const el = e.currentTarget as Element;
      removeHighlight(el);
      enterCounters.current.set(el, 0);

      const ev = draggingEventRef.current;
      if (!ev || !scrollRef.current) return;

      const newStart = lastSnappedTimeRef.current || ev.start;
      const dur      = durationMinutes(ev.start, ev.end);
      const [sh, sm] = newStart.split(':').map(Number);
      const endTotal = sh * 60 + sm + dur;
      const newEnd   = minutesToTimeStr(endTotal);

      dispatch({
        type: 'UPDATE_EVENT',
        payload: { ...ev, date: dateStr, start: newStart, end: newEnd },
      });
    },
  }), [dispatch]);

  // ── Month cell drop props ─────────────────────────────────────────────────
  const getMonthCellDropProps = useCallback((dateStr: string) => ({
    onDragEnter: (e: React.DragEvent) => {
      e.preventDefault();
      const el = e.currentTarget as Element;
      const count = (enterCounters.current.get(el) ?? 0) + 1;
      enterCounters.current.set(el, count);
      if (count === 1) addHighlight(el);
    },

    onDragLeave: (e: React.DragEvent) => {
      const el = e.currentTarget as Element;
      const count = Math.max((enterCounters.current.get(el) ?? 1) - 1, 0);
      enterCounters.current.set(el, count);
      if (count === 0) removeHighlight(el);
    },

    onDragOver: (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
    },

    onDrop: (e: React.DragEvent) => {
      e.preventDefault();
      const el = e.currentTarget as Element;
      removeHighlight(el);
      enterCounters.current.set(el, 0);

      const ev = draggingEventRef.current;
      if (!ev) return;

      dispatch({
        type: 'UPDATE_EVENT',
        payload: { ...ev, date: dateStr },
      });
    },
  }), [dispatch]);

  return { getChipDragProps, getWeekColDropProps, getMonthCellDropProps };
}
